import { revalidateTag } from 'next/cache';

type Product = {
  id: number;
  name: string;
  sku: string;
  price: number;
  inventory: number;
  availability: 'In stock' | 'Low stock' | 'Backorder';
};

type SyncStatus = {
  lastStartedAt: string | null;
  lastCompletedAt: string | null;
  inProgress: boolean;
};

let catalogVersion = 1;

let products: Product[] = [
  {
    id: 1,
    name: 'Aquila Pro Laptop',
    sku: 'LAP-AQUILA-PRO',
    price: 1299,
    inventory: 18,
    availability: 'In stock'
  },
  {
    id: 2,
    name: 'Nimbus Fold Phone',
    sku: 'PHN-NIMBUS-FOLD',
    price: 899,
    inventory: 7,
    availability: 'Low stock'
  },
  {
    id: 3,
    name: 'Atlas 11 Tablet',
    sku: 'TAB-ATLAS-11',
    price: 549,
    inventory: 0,
    availability: 'Backorder'
  },
  {
    id: 4,
    name: 'Pulse ANC Headphones',
    sku: 'AUD-PULSE-ANC',
    price: 249,
    inventory: 35,
    availability: 'In stock'
  },
  {
    id: 5,
    name: 'Vector Sport Watch',
    sku: 'WRB-VECTOR-SPORT',
    price: 329,
    inventory: 12,
    availability: 'In stock'
  }
];

const syncStatus: SyncStatus = {
  lastStartedAt: null,
  lastCompletedAt: null,
  inProgress: false
};

function cloneProducts() {
  return products.map((product) => ({ ...product }));
}

function deriveAvailability(inventory: number): Product['availability'] {
  if (inventory <= 0) {
    return 'Backorder';
  }

  if (inventory < 10) {
    return 'Low stock';
  }

  return 'In stock';
}

function createSyncedProducts(version: number): Product[] {
  return products.map((product, index) => {
    const inventoryShift = ((version + index) % 7) - 3;
    const nextInventory = Math.max(0, product.inventory + inventoryShift * 4);
    const priceDelta = ((version + index) % 3) * 15;

    return {
      ...product,
      price: product.price + priceDelta,
      inventory: nextInventory,
      availability: deriveAvailability(nextInventory)
    };
  });
}

export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));
  return cloneProducts();
}

export async function getCatalogSyncStatus() {
  return { ...syncStatus };
}

export async function syncLatestCatalog() {
  if (syncStatus.inProgress) {
    return false;
  }

  syncStatus.inProgress = true;
  syncStatus.lastStartedAt = new Date().toISOString();

  void (async () => {
    await new Promise((resolve) => setTimeout(resolve, 1500));

    catalogVersion += 1;
    products = createSyncedProducts(catalogVersion);
    syncStatus.inProgress = false;
    syncStatus.lastCompletedAt = new Date().toISOString();
    revalidateTag('products', 'max');
  })();

  return true;
}

