function formatTimestamp(value: string | null) {
  if (!value) {
    return 'Not yet synced';
  }

  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
    timeZone: 'UTC'
  }).format(new Date(value));
}

